@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h3>Notepad</h3>

<textarea @bind="content" @bind:event="oninput" rows="15" style="width:100%;" />

<div style="margin-top: 0.5rem; display: flex; align-items: center; gap: 1rem;">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span>Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string lastSavedContent = string.Empty;
    private DateTime? lastSavedAt;
    private Timer? autoSaveTimer;
    private IJSObjectReference? module;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import", "./Components/Pages/Notepad.razor.js");
            var saved = await module.InvokeAsync<string?>("load");
            if (!string.IsNullOrEmpty(saved))
            {
                content = saved;
                lastSavedContent = saved;
                StateHasChanged();
            }

            await module.InvokeVoidAsync("registerBeforeUnload", DotNetObjectReference.Create(this));

            autoSaveTimer = new Timer(async _ => await InvokeAsync(SaveNow), null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    [JSInvokable]
    public bool HasUnsavedChanges() => content != lastSavedContent;

    private async Task SaveNow()
    {
        if (module is null) return;
        await module.InvokeVoidAsync("save", content);
        lastSavedContent = content;
        lastSavedAt = DateTime.Now;
        StateHasChanged();
    }

    private async Task Clear()
    {
        content = string.Empty;
        lastSavedContent = string.Empty;
        lastSavedAt = null;
        if (module is not null)
        {
            await module.InvokeVoidAsync("clear");
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
        {
            await autoSaveTimer.DisposeAsync();
        }
        if (module is not null)
        {
            await module.InvokeVoidAsync("dispose");
            await module.DisposeAsync();
        }
    }
}

const storageKey = "notepad-content";
let dotNetRef = null;

export function save(content) {
    localStorage.setItem(storageKey, content);
}

export function load() {
    return localStorage.getItem(storageKey);
}

export function clear() {
    localStorage.removeItem(storageKey);
}

export function registerBeforeUnload(ref) {
    dotNetRef = ref;
    window.addEventListener("beforeunload", onBeforeUnload);
}

function onBeforeUnload(e) {
    if (dotNetRef && dotNetRef.invokeMethod("HasUnsavedChanges")) {
        e.preventDefault();
        e.returnValue = "";
    }
}

export function dispose() {
    window.removeEventListener("beforeunload", onBeforeUnload);
    dotNetRef = null;
}

